import { calcCssBackground, mergeStyleSets } from '@kyokuya/core-util'
import React from 'react'
import { DuelPlayerContainer } from './container/DuelPlayerContainer'
import { GameBoard } from './container/GameBoard'
import { GameOverlay } from './container/GameOverlay'
import { GameToolbar } from './container/GameToolbar'
import { GomokuActionType, useGomokuContext } from './context'

export const GomokuGameMain: React.FC = () => {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const classes = useStyles()

  const { dispatch } = useGomokuContext()
  React.useEffect(() => {
    const beforeunload = (): void => dispatch({ type: GomokuActionType.PAUSE })
    window.addEventListener('beforeunload', beforeunload)
    return () => window.removeEventListener('beforeunload', beforeunload)
  }, [dispatch])

  return (
    <div ref={containerRef} className={classes.container}>
      <div className={classes.header}>
        <DuelPlayerContainer containerRef={containerRef} />
        <GameToolbar containerRef={containerRef} />
      </div>
      <div className={classes.main}>
        <GameBoard overlay={<GameOverlay />} />
      </div>
    </div>
  )
}

const useStyles = () => {
  const [boardBackground] = useGomokuContext(({ state }) => [state.preference.boardBackground])

  return mergeStyleSets({
    container: {
      boxSizing: 'border-box',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center',
      width: '100%',
    },
    header: {
      boxSizing: 'border-box',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      width: '100%',
      padding: '2vmin',
    },
    main: {
      boxSizing: 'border-box',
      height: '96vmin',
      width: '96vmin',
      background: calcCssBackground(boardBackground),
      backgroundSize: 'cover',
      '@media (min-width: 1367px)': {
        width: '60vmin',
        height: '60vmin',
      },
    },
  })
}
