import { useSyncState } from '@guanghechen/react-hooks'
import type { IColor, IColorOrImage } from '@kyokuya/core-util'
import { mergeStyleSets } from '@kyokuya/core-util'
import React from 'react'
import { GomokuSettingsBackground } from './GomokuSettingsBackground'
import { GomokuSettingsBorder } from './GomokuSettingsBorder'
import { GameSettingsGomokuSize } from './GomokuSettingsSize'

export interface IGameSettingsData {
  size: number
  background: IColorOrImage
  border: IColor
}

export interface IGameSettingsHandle {
  getData(): IGameSettingsData
  reset(): void
}

export interface IGameSettingsProps {
  disabled: boolean
  size: number
  background: IColorOrImage
  border: IColor
}

export type GameSettings = React.ElementRef<typeof GameSettings>
// eslint-disable-next-line @typescript-eslint/no-redeclare
export const GameSettings = React.forwardRef<IGameSettingsHandle, IGameSettingsProps>(
  GameSettingsRenderer,
)

function GameSettingsRenderer(
  props: IGameSettingsProps,
  ref: React.ForwardedRef<IGameSettingsHandle>,
): React.ReactElement | null {
  const [size, setSize] = useSyncState<number>(props.size)
  const [background, setBackground] = useSyncState<IColorOrImage>(props.background)
  const [border, setBorder] = useSyncState<IColor>(props.border)

  React.useImperativeHandle(ref, () => ({
    getData: () => ({ size, background, border }),
    reset: () => {
      setSize(props.size)
      setBackground(props.background)
    },
  }))

  const classes = useStyles()

  return (
    <div className={classes.container}>
      <GameSettingsGomokuSize
        className={classes.item}
        disabled={props.disabled}
        size={size}
        onSizeChange={setSize}
      />
      <GomokuSettingsBackground
        className={classes.item}
        disabled={props.disabled}
        background={background}
        onBackgroundChange={setBackground}
      />
      <GomokuSettingsBorder
        className={classes.item}
        disabled={props.disabled}
        border={border}
        onBorderChange={setBorder}
      />
    </div>
  )
}

const useStyles = () => {
  return mergeStyleSets({
    container: {
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      margin: '0 auto 1rem',
    },
    item: {
      lineHeight: '3rem',
      margin: '0 1rem',
    },
  })
}
