import { cx, keyframes } from '@emotion/css'
import type { IColorOrImage } from '@kyokuya/core-util'
import { calcCssBackground, mergeStyleSets } from '@kyokuya/core-util'
import AccessAlarmIcon from '@mui/icons-material/AccessAlarm'
import React from 'react'
import type { GomokuPlayerType } from '../context'

export interface IDuelPlayerProps {
  position: 'left' | 'right'
  name: string
  type: GomokuPlayerType
  disabled: boolean
  thinking: boolean
  running: boolean
  avatar: IColorOrImage
  className?: string
  onEdit(): void
}

export const DuelPlayer: React.FC<IDuelPlayerProps> = props => {
  const classes = useStyles(
    props.position,
    props.avatar,
    props.disabled,
    props.thinking,
    props.running,
  )
  return (
    <div className={cx(classes.container, props.className)} onClick={props.onEdit}>
      <div className={classes.userWrapper}>
        <span className={classes.name}>{props.name}</span>
        <span className={classes.type}>{props.type}</span>
      </div>
      <div className={classes.avatar}>
        <AccessAlarmIcon className={classes.thinkingIcon} />
      </div>
    </div>
  )
}

const useStyles = (
  position: 'left' | 'right',
  avatar: IColorOrImage,
  disabled: boolean,
  thinking: boolean,
  running: boolean,
) => {
  return React.useMemo(
    () =>
      mergeStyleSets({
        container: {
          display: 'flex',
          flexDirection: position === 'left' ? 'row' : 'row-reverse',
          justifyContent: 'flex-end',
          alignItems: 'center',
          lineHeight: '16px',
          cursor: disabled ? 'default' : 'pointer',
        },
        avatar: {
          position: 'relative',
          width: 32,
          height: 32,
          borderRadius: '50%',
          margin: position === 'left' ? '0 0 0 6px' : '0 6px 0 0',
          background: calcCssBackground(avatar),
          backgroundSize: 'cover',
        },
        userWrapper: {
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          alignItems: 'center',
          lineHeight: '16px',
        },
        name: {
          display: 'flex',
          alignItems: 'center',
          color: '#4682b4',
          fontSize: 16,
          userSelect: 'none',
        },
        thinkingIcon: {
          '&&': {
            position: 'absolute',
            top: 0,
            left: position === 'left' ? undefined : -20,
            right: position === 'left' ? -20 : undefined,
            display: 'inline-block',
            visibility: thinking ? 'visible' : 'hidden',
            transition: 'translate(0, -50%)',
            width: 16,
            height: 16,
            color: '#69696e',
            userSelect: 'none',
            animation: running
              ? `1s ease-in 0s ${animations.thinkingIcon} infinite alternate both`
              : undefined,
          },
        },
        type: {
          margin: '4px 0',
          fontSize: 14,
          userSelect: 'none',
        },
      }),
    [position, avatar, disabled, thinking, running],
  )
}

const animations = {
  thinkingIcon: keyframes({
    '0%': {
      transform: 'rotate(-30deg) scale(1.0)',
    },
    '50%': {
      transform: 'rotate(0deg) scale(1.2)',
    },
    '100%': {
      transform: 'rotate(30deg) scale(1.0)',
    },
  }),
}
