import PropTypes from 'prop-types'
import React from 'react'
import type { IGomokuState } from './context'
import { GomokuContextProvider } from './context'
import { GomokuGameMain } from './GomokuGameMain'

export interface IGomokuGameProps {
  storageKey?: string
  initialState?: Partial<IGomokuState> | Promise<Partial<IGomokuState>>
}

export const GomokuGame: React.FC<IGomokuGameProps> = props => {
  return (
    <GomokuContextProvider storageKey={props.storageKey} initialData={props.initialState}>
      <GomokuGameMain />
    </GomokuContextProvider>
  )
}

GomokuGame.propTypes = {
  storageKey: PropTypes.string.isRequired,
}
