import { cx } from '@emotion/css'
import { useEvent } from '@kyokuya/react-hooks'
import type { SelectChangeEvent } from '@mui/material'
import { MenuItem, Select } from '@mui/material'
import React from 'react'
import { GomokuPlayerType } from '../context'
import { usePlayerSettingsStyle } from './styles'

export interface IPlayerTypeSettings {
  type: GomokuPlayerType
  disabled: boolean
  className?: string
  label?: React.ReactNode
  onTypeChange(type: GomokuPlayerType): void
}

export const PlayerTypeSettings: React.FC<IPlayerTypeSettings> = props => {
  const events = {
    onPlayerTypeChange: useEvent((e: SelectChangeEvent<GomokuPlayerType>): void => {
      const value: GomokuPlayerType = e.target.value as GomokuPlayerType
      props.onTypeChange(value)
    }),
  }

  const classes = usePlayerSettingsStyle()
  return (
    <div className={cx(classes.formItem, props.className)}>
      <span className={classes.formItemLabel}>{props.label}</span>
      <Select<GomokuPlayerType>
        className={classes.formItemValue}
        required={true}
        variant="standard"
        value={props.type}
        disabled={props.disabled}
        onChange={events.onPlayerTypeChange}
      >
        <MenuItem value={GomokuPlayerType.HUMAN}>{GomokuPlayerType.HUMAN}</MenuItem>
        <MenuItem value={GomokuPlayerType.COMPUTER}>{GomokuPlayerType.COMPUTER}</MenuItem>
        <MenuItem value={GomokuPlayerType.STUPID_COMPUTER}>
          {GomokuPlayerType.STUPID_COMPUTER}
        </MenuItem>
      </Select>
    </div>
  )
}
