import { useSyncState } from '@guanghechen/react-hooks'
import { useEvent } from '@kyokuya/react-hooks'
import React from 'react'
import { ComputerPlayerSettings } from '../component/ComputerPlayerSettings'
import { HumanPlayerSetting } from '../component/HumanPlayerSetting'
import { StupidComputerPlayerSettings } from '../component/StupidComputerPlayerSettings'
import { GomokuActionType, GomokuPlayerType, useGomokuContext } from '../context'

interface IPlayerSettingsContainerHandle {
  saveChanges(): void
}

interface IPlayerSettingsContainerProps {
  playerId: number
  disabled: boolean
  ref?: any
}

export type PlayerSettingsContainer = React.ElementRef<typeof PlayerSettingsContainer>
// eslint-disable-next-line @typescript-eslint/no-redeclare
export const PlayerSettingsContainer = React.forwardRef<
  IPlayerSettingsContainerHandle,
  IPlayerSettingsContainerProps
>(PlayerSettingsContainerRenderer)

function PlayerSettingsContainerRenderer(
  props: IPlayerSettingsContainerProps,
  ref: React.ForwardedRef<IPlayerSettingsContainerHandle>,
): React.ReactElement | null {
  const [player, dispatch] = useGomokuContext(({ state, dispatch }) => [
    state.players[props.playerId],
    dispatch,
  ])
  const [name, setName] = useSyncState<string>(player.name)
  const [type, setType] = useSyncState<GomokuPlayerType>(player.type)

  const events = {
    onNameChange: useEvent((name: string): void => setName(name)),
    onTypeChange: useEvent((type: GomokuPlayerType): void => setType(type)),
    saveChanges: useEvent((): void => {
      dispatch({
        type: GomokuActionType.MODIFY_PLAYER,
        payload: {
          id: props.playerId,
          type,
          name: name || player.name,
        },
      })
    }),
  }

  React.useImperativeHandle(ref, () => ({ saveChanges: events.saveChanges }))

  switch (type) {
    case GomokuPlayerType.HUMAN:
      return (
        <HumanPlayerSetting
          name={name}
          type={type}
          disabled={props.disabled}
          onNameChange={events.onNameChange}
          onTypeChange={events.onTypeChange}
        />
      )
    case GomokuPlayerType.STUPID_COMPUTER:
      return (
        <StupidComputerPlayerSettings
          name={name}
          type={type}
          disabled={props.disabled}
          onNameChange={events.onNameChange}
          onTypeChange={events.onTypeChange}
        />
      )
    case GomokuPlayerType.COMPUTER:
      return (
        <ComputerPlayerSettings
          name={name}
          type={type}
          disabled={props.disabled}
          onNameChange={events.onNameChange}
          onTypeChange={events.onTypeChange}
        />
      )
    default:
      return <React.Fragment />
  }
}
