import { cx } from '@emotion/css'
import { useEvent } from '@kyokuya/react-hooks'
import { TextField } from '@mui/material'
import React from 'react'
import { usePlayerSettingsStyle } from './styles'

export interface IPlayerNameSetting {
  name: string
  disabled: boolean
  className?: string
  label?: React.ReactNode
  onNameChange(name: string): void
}

export const PlayerNameSetting: React.FC<IPlayerNameSetting> = props => {
  const [name, setName] = React.useState<string>(props.name)

  const events = {
    onPlayerNameChange: useEvent((e: React.ChangeEvent<HTMLInputElement>): void => {
      setName(e.target.value)
    }),
    onPlayerNameBlur: useEvent((): void => {
      props.onNameChange(name)
    }),
  }

  React.useEffect(() => {
    setName(props.name)
  }, [props.name])

  const classes = usePlayerSettingsStyle()
  return (
    <div className={cx(classes.formItem, props.className)}>
      <span className={classes.formItemLabel}>{props.label}</span>
      <TextField
        className={classes.formItemValue}
        required={true}
        variant="standard"
        value={name}
        disabled={props.disabled}
        onChange={events.onPlayerNameChange}
        onBlur={events.onPlayerNameBlur}
      />
    </div>
  )
}
