import { mergeStyleSets } from '@kyokuya/core-util'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { useEvent } from '@kyokuya/react-hooks'
import { Button, Dialog, DialogActions, DialogContent } from '@mui/material'
import React from 'react'
import { DuelPlayer } from '../component/DuelPlayer'
import { useGomokuContext } from '../context'
import { PlayerSettingsContainer } from './PlayerSettingsContainer'

export interface IDuelPlayerContainerProps {
  containerRef: React.RefObject<HTMLDivElement>
}

export const DuelPlayerContainer: React.FC<IDuelPlayerContainerProps> = props => {
  const playerSettingRef = React.useRef<PlayerSettingsContainer>(null)
  const [[player0, player1], gameStatus, mover] = useGomokuContext(({ state }) => [
    state.players,
    state.gameStatus,
    state.mover,
  ])
  const [editingPlayerId, setEditingPlayerId] = React.useState<number | null>(null)

  const isRunning: boolean = gameStatus === GameRunningStatus.RUNNING
  const isEditable: boolean = gameStatus === GameRunningStatus.PENDING
  const isDialogVisible: boolean = editingPlayerId !== null

  const events = {
    onCancel: useEvent((): void => setEditingPlayerId(null)),
    onConfirm: useEvent((): void => {
      playerSettingRef.current?.saveChanges()
      setEditingPlayerId(null)
    }),
    onEditPlayer0: useEvent((): void => setEditingPlayerId(0)),
    onEditPlayer1: useEvent((): void => setEditingPlayerId(1)),
  }

  const classes = useStyles()

  return (
    <div className={classes.container}>
      <DuelPlayer
        key="player0"
        position="left"
        className={classes.player0}
        name={player0.name}
        type={player0.type}
        avatar={player0.preferenceSettings.pieceFillStyle}
        disabled={!isEditable}
        running={isRunning}
        thinking={mover === 0}
        onEdit={events.onEditPlayer0}
      />
      <span className={classes.versus}>VS</span>
      <DuelPlayer
        key="player1"
        position="right"
        className={classes.player1}
        name={player1.name}
        type={player1.type}
        avatar={player1.preferenceSettings.pieceFillStyle}
        disabled={!isEditable}
        running={isRunning}
        thinking={mover === 1}
        onEdit={events.onEditPlayer1}
      />
      <Dialog
        container={props.containerRef.current}
        open={isDialogVisible}
        onClose={events.onCancel}
        aria-labelledby="edit-player"
      >
        <DialogContent>
          <PlayerSettingsContainer
            ref={playerSettingRef}
            playerId={editingPlayerId ?? 0}
            disabled={!isEditable}
          />
        </DialogContent>
        <DialogActions>
          <Button color="inherit" onClick={events.onCancel}>
            Cancel
          </Button>
          <Button color="primary" disabled={!isEditable} onClick={events.onConfirm}>
            Confirm
          </Button>
        </DialogActions>
      </Dialog>
    </div>
  )
}

const useStyles = () => {
  return mergeStyleSets({
    container: {
      display: 'flex',
      alignItems: 'center',
      maxWidth: 'min(90vw, 400px)',
      height: '3rem',
      width: '100%',
      margin: 'auto',
    },
    player0: {
      flex: '1 1 0',
      display: 'flex',
    },
    player1: {
      flex: '1 1 0',
      display: 'flex',
    },
    versus: {
      flex: '0 0 auto',
      margin: '0 36px',
    },
  })
}
