import { createUseSelectableContext, pick } from '@kyokuya/core-util'
import { createPersistProvider } from '@kyokuya/react-storage'
import React from 'react'
import type { IGomokuAction } from './action'
import { gomokuReducer } from './reducer'
import type { IGomokuData, IGomokuState } from './state'
import { initGomokuState } from './state'

export interface IGomokuContext {
  state: IGomokuState
  dispatch: React.Dispatch<IGomokuAction>
}

const GomokuContextType = React.createContext<IGomokuContext>({
  state: initGomokuState(),
  dispatch: () => {
    throw new Error('[GomokuContextType] dispatch is not available yet.')
  },
})

export const GomokuContextProvider = createPersistProvider<
  IGomokuState,
  IGomokuAction,
  IGomokuData
>({
  ContextType: GomokuContextType,
  ContextName: 'GomokuContext',
  initState: initGomokuState,
  reducer: gomokuReducer,
  serialize: latestData =>
    pick(latestData, [
      'MAX_ROW',
      'MAX_COL',
      'winner',
      'instructions',
      'gameTick',
      'players',
      'preference',
    ]),
})

export const useGomokuContext = createUseSelectableContext(GomokuContextType)
