import invariant from '@guanghechen/invariant'
import type { IColorOrImage } from '@kyokuya/core-util'
import { DOUBLE_PI, calcCssColor } from '@kyokuya/core-util'

export interface IGomokuPieceDrawer {
  /**
   * Draw gomoku piece.
   * @param context
   * @param playerId
   * @param x
   * @param y
   * @param radius
   */
  drawPieces(
    context: CanvasRenderingContext2D,
    playerId: number,
    radius: number,
    positions: Array<{ x: number; y: number }>,
  ): Promise<void> | void
}

export interface IGomokuPiecePreferenceSettings {
  pieceFillStyle: IColorOrImage
  pieceStrokeStyle?: string
}

export type IPreferenceSettingsProvider = (playerId: number) => IGomokuPiecePreferenceSettings

export class GomokuPieceDrawer implements IGomokuPieceDrawer {
  public readonly getPreferenceSettings: IPreferenceSettingsProvider

  constructor(getPreferenceSettings: IPreferenceSettingsProvider) {
    this.getPreferenceSettings = getPreferenceSettings
  }

  public drawPieces(
    context: CanvasRenderingContext2D,
    playerId: number,
    radius: number,
    pieces: Array<{ x: number; y: number }>,
  ): Promise<void> {
    const diameter: number = radius * 2
    const { pieceFillStyle, pieceStrokeStyle } = this.getPreferenceSettings(playerId)

    // eslint-disable-next-line no-param-reassign
    context.strokeStyle = pieceStrokeStyle ?? ''

    switch (pieceFillStyle.prefer) {
      case 'color': {
        invariant(pieceFillStyle.color != null, '[drawPiece] color is not defined')
        // eslint-disable-next-line no-param-reassign
        context.fillStyle = calcCssColor(pieceFillStyle.color)

        for (const { x, y } of pieces) {
          context.beginPath()
          context.arc(x, y, radius, 0, DOUBLE_PI, false)
          context.closePath()
          context.stroke()
          context.fill()
        }
        return Promise.resolve()
      }
      case 'image': {
        invariant(pieceFillStyle.imageUrl != null, '[drawPiece] imageUrl is not defined')
        const img = document.createElement('img')
        img.src = pieceFillStyle.imageUrl
        return new Promise(resolve => {
          img.onload = () => {
            for (const { x, y } of pieces) {
              context.save()
              context.beginPath()
              context.arc(x, y, radius, 0, DOUBLE_PI, false)
              context.closePath()
              context.clip()
              context.drawImage(
                img,
                0,
                0,
                img.width,
                img.height,
                x - radius,
                y - radius,
                diameter,
                diameter,
              )
              context.restore()
            }
            resolve()
          }
        })
      }
      default:
        return Promise.resolve()
    }
  }
}
