import { cx } from '@emotion/css'
import { BackgroundPicker } from '@kyokuya/core-component'
import type { IColorOrImage } from '@kyokuya/core-util'
import { calcCssBackground, mergeStyleSets } from '@kyokuya/core-util'
import { useEvent } from '@kyokuya/react-hooks'
import { Button } from '@mui/material'
import React from 'react'
import { defaultGomokuState } from '../context'

export interface IGameSettingsBackgroundProps {
  disabled: boolean
  background: IColorOrImage
  className?: string
  onBackgroundChange?(background: IColorOrImage): void
}

export const GomokuSettingsBackground: React.FC<IGameSettingsBackgroundProps> = props => {
  const { disabled } = props
  const [background, setBackground] = React.useState<IColorOrImage>(props.background)
  const [pickerVisible, setPickerVisible] = React.useState<boolean>(false)

  const events = {
    onTogglePickerVisible: useEvent(() => {
      if (disabled) return
      setPickerVisible(v => !v)
    }),
    onBackgroundChange: useEvent((nextBackground: IColorOrImage): void => {
      if (disabled) return
      setBackground(nextBackground)
      props.onBackgroundChange?.(nextBackground)
    }),
    onResetColor: useEvent(() => {
      if (disabled) return
      const nextBackground: IColorOrImage = { ...defaultGomokuState.preference.boardBackground }
      setBackground(nextBackground)
      props.onBackgroundChange?.(nextBackground)
    }),
  }

  const classes = useStyles(background, disabled)
  return (
    <div className={cx(classes.container, props.className)}>
      <span className={classes.label}>Background:</span>
      <div className={classes.swatch} onClick={events.onTogglePickerVisible}>
        <div className={classes.colorSquare} />
      </div>
      <BackgroundPicker
        visible={pickerVisible}
        background={background}
        onVisibleChange={setPickerVisible}
        onBackgroundChange={events.onBackgroundChange}
      />
      <div>
        <Button disabled={disabled} className={classes.resetColorBth} onClick={events.onResetColor}>
          (reset)
        </Button>
      </div>
    </div>
  )
}

const useStyles = (background: IColorOrImage, disabled: boolean) => {
  return mergeStyleSets({
    container: {
      display: 'flex',
      alignItems: 'center',
    },
    label: {
      userSelect: 'none',
    },
    swatch: {
      display: 'inline-block',
      padding: 3,
      border: '1px solid rgba(0,0,0,.2)',
      borderRadius: '1px',
      background: '#fff',
      cursor: disabled ? 'default' : 'pointer',
      '&&': {
        marginLeft: '1rem',
      },
    },
    colorSquare:
      background.prefer === 'image'
        ? {
            width: 32,
            height: 32,
            borderRadius: 2,
            background: calcCssBackground(background),
            backgroundSize: 'cover',
          }
        : {
            width: 32,
            height: 12,
            borderRadius: 2,
            background: calcCssBackground(background),
            backgroundSize: 'cover',
          },
    colorPicker: {
      '&&': {
        border: 'none !important',
        borderRadius: '0px !important',
        boxShadow: 'none !important',
      },
    },
    resetColorBth: {
      '&&': {
        textTransform: 'none',
      },
    },
  })
}
