export interface IGamePageProps {
  title: string
  description?: string
  children: React.ReactNode
}

export const GamePage: React.FC<IGamePageProps> = props => {
  const [author, copyright] = useSiteContext(({ state }) => [state.author, state.copyright])
  const classes = useStyles()

  return (
    <React.Fragment>
      <SeoPageDescription title={props.title} description={props.description} />
      <div className={classes.container}>
        <header className={classes.header}>
          <h1>{props.title}</h1>
        </header>
        <main className={classes.main}>
          <div className={classes.content}>{props.children}</div>
        </main>
        <footer className={classes.footer}>
          <div className={classes.copyright}>
            <span key="date">
              © {copyright.date} {author.name}
            </span>
            <span key="motto">{author.motto}</span>
          </div>
        </footer>
      </div>
    </React.Fragment>
  )
}

