import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import type { IColor, IColorOrImage } from '@kyokuya/core-util'
import { deepAssign } from '@kyokuya/core-util'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import type { IGomokuPlayer } from '../types'
import type { GomokuInstructionType } from './constant'
import { GomokuPlayerType } from './constant'
import { checkWinner, runInstructs } from './util'

export type IGomokuInstruction =
  | {
      type: GomokuInstructionType.MOVE
      payload: IGomokuPiece
      timestamp: string // ISO string
    }
  | {
      type: GomokuInstructionType.RETRACT
      payload: number // Retracted steps.
      timestamp: string // ISO string
    }

export interface IGomokuState {
  /**
   * The number of rows of the Gomoku game board.
   */
  MAX_ROW: number
  /**
   * The number of columns of the Gomoku game board.
   */
  MAX_COL: number
  /**
   * Game status.
   */
  gameStatus: GameRunningStatus
  /**
   * Who win the games. -1 represents game not finished or it is a tie.
   */
  winner: -1 | 0 | 1
  /**
   * The player who currently needs to make a move.
   */
  mover: 0 | 1
  /**
   * The pieces on the gomoku board.
   */
  pieces: ReadonlyArray<IGomokuPiece>
  /**
   * Player instructions.
   */
  instructions: ReadonlyArray<IGomokuInstruction>
  /**
   * Used to judge if the game has restarted.
   */
  gameTick: number
  /**
   * Times of attempt on the current game.
   */
  attemptTick: number
  /**
   * Playing players.
   */
  players: IGomokuPlayer[]
  /**
   * Customized settings.
   */
  preference: {
    borderColor: IColor
    locatePointColor: IColor
    boardBackground: IColorOrImage
  }
}

export type IGomokuData = IGomokuState

export function initGomokuState(
  customizedData?: Partial<IGomokuData> | null,
  baseState: Readonly<IGomokuState> = defaultGomokuState,
): IGomokuState {
  const {
    MAX_ROW = baseState.MAX_ROW,
    MAX_COL = baseState.MAX_COL,
    instructions = baseState.instructions.slice(),
    gameTick = baseState.gameTick,
  } = { ...customizedData }

  const pieces = runInstructs(instructions)
  const winner = checkWinner(pieces, MAX_ROW, MAX_COL)
  const mover: 0 | 1 = (pieces.length & 1) as 0 | 1
  const gameStatus: GameRunningStatus =
    winner < 0
      ? instructions.length > 0
        ? GameRunningStatus.PAUSED
        : GameRunningStatus.PENDING
      : GameRunningStatus.FINISHED

  return {
    MAX_ROW,
    MAX_COL,
    gameStatus,
    winner,
    mover,
    pieces,
    instructions,
    gameTick,
    attemptTick: 0,
    players: [
      deepAssign(baseState.players[0], customizedData?.players?.[0]),
      deepAssign(baseState.players[1], customizedData?.players?.[1]),
    ],
    preference: deepAssign(baseState.preference, customizedData?.preference),
  }
}

